1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	const CURSED_SURCHARGE_PERCENT = 50;
4	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
17	const BLOCK_SIZE = 3;
18	const BLOCK_PRICE = 60;
19	
20	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];
21	
22	const sumItemPremiums = (items: any[]): number =>
23	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
24	
25	const groupByType = (items: any[]): Record<string, any[]> =>
26	  items.reduce((groups, item) => {
27	    (groups[item.type] ||= []).push(item);
28	    return groups;
29	  }, {} as Record<string, any[]>);
30	
31	const isCompleteBlock = (type: string, group: any[]): boolean =>
32	  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;
33	
34	const groupPremium = (type: string, group: any[]): number =>
35	  isCompleteBlock(type, group) ? BLOCK_PRICE : sumItemPremiums(group);
36	
37	const calculateBasePremium = (items: any[]): number =>
38	  Object.entries(groupByType(items)).reduce(
39	    (total, [type, group]) => total + groupPremium(type, group),
40	    0
41	  );
42	
43	const percentOf = (amount: number, percent: number): number =>
44	  (amount * percent) / 100;
45	
46	const addPercent = (amount: number, percent: number): number =>
47	  amount + percentOf(amount, percent);
48	
49	const ITEM_SURCHARGE_RULES: { applies: (item: any) => boolean; percent: number }[] = [
50	  { applies: (item) => item.cursed, percent: CURSED_SURCHARGE_PERCENT },
51	  {
52	    applies: (item) => item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
53	    percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
54	  },
55	];
56	
57	const itemSurcharge = (item: any): number => {
58	  const base = itemBasePremium(item);
59	  return ITEM_SURCHARGE_RULES.reduce(
60	    (sum, rule) => sum + (rule.applies(item) ? percentOf(base, rule.percent) : 0),
61	    0
62	  );
63	};
64	
65	const calculateItemSurcharges = (items: any[]): number =>
66	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
67	
68	const quotePremium = (items: any[]): number => {
69	  const policyBase = calculateBasePremium(items);
70	  const surcharges = calculateItemSurcharges(items);
71	  const withFirstInsurance = addPercent(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
72	  return Math.ceil(withFirstInsurance + surcharges + PROCESSING_FEE);
73	};
74	
75	export const runScenario = (scenario: any): unknown => {
76	  const items = scenario.steps[0].items;
77	  return { results: [{ premium: quotePremium(items) }] };
78	};
